                    cells.append((cr,cc))
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if 0 <= nr < inp.shape[0] and 0 <= nc < inp.shape[1] and (nr,nc) not in visited and inp[nr,nc] == color:
                            visited.add((nr,nc))
                            queue.append((nr,nc))

                rows = [r for r,c in cells]
                cols = [c for r,c in cells]
                min_r, max_r = min(rows), max(rows)
                min_c, max_c = min(cols), max(cols)

